export const submitCourseModuleAttempt = async (
  moduleId: number,
  submitModuleAttemptBody: SubmitModuleAttemptBody,
  options?: RequestInit,
): Promise<ModuleAttemptResult> => {
  return customFetch<ModuleAttemptResult>(
    getSubmitCourseModuleAttemptUrl(moduleId),
    {
      ...options,
      method: "POST",
      headers: { "Content-Type": "application/json", ...options?.headers },
      body: JSON.stringify(submitModuleAttemptBody),
    },
  );
};

export const getSubmitCourseModuleAttemptMutationOptions = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof submitCourseModuleAttempt>>,
    TError,
    { moduleId: number; data: BodyType<SubmitModuleAttemptBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof submitCourseModuleAttempt>>,
  TError,
  { moduleId: number; data: BodyType<SubmitModuleAttemptBody> },
  TContext
> => {
  const mutationKey = ["submitCourseModuleAttempt"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof submitCourseModuleAttempt>>,
    { moduleId: number; data: BodyType<SubmitModuleAttemptBody> }
  > = (props) => {
    const { moduleId, data } = props ?? {};

    return submitCourseModuleAttempt(moduleId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SubmitCourseModuleAttemptMutationResult = NonNullable<
  Awaited<ReturnType<typeof submitCourseModuleAttempt>>
>;
export type SubmitCourseModuleAttemptMutationBody =
  BodyType<SubmitModuleAttemptBody>;
export type SubmitCourseModuleAttemptMutationError = ErrorType<void>;

/**
 * @summary Submit answers for a module attempt and get score + per-question feedback
 */
export const useSubmitCourseModuleAttempt = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof submitCourseModuleAttempt>>,
    TError,
    { moduleId: number; data: BodyType<SubmitModuleAttemptBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof submitCourseModuleAttempt>>,
  TError,
  { moduleId: number; data: BodyType<SubmitModuleAttemptBody> },
  TContext
> => {
  return useMutation(getSubmitCourseModuleAttemptMutationOptions(options));
};

/**
 * @summary Get the current user's history for a specific quiz
 */
export const getGetUserQuizProgressUrl = (quizId: number) => {
  return `/api/user/progress/${quizId}`;
};

export const getUserQuizProgress = async (
  quizId: number,
  options?: RequestInit,
): Promise<UserQuizProgress> => {
  return customFetch<UserQuizProgress>(getGetUserQuizProgressUrl(quizId), {
    ...options,
    method: "GET",
  });
};

export const getGetUserQuizProgressQueryKey = (quizId: number) => {
  return [`/api/user/progress/${quizId}`] as const;
};

export const getGetUserQuizProgressQueryOptions = <
  TData = Awaited<ReturnType<typeof getUserQuizProgress>>,
  TError = ErrorType<void>,
>(
  quizId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getUserQuizProgress>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetUserQuizProgressQueryKey(quizId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getUserQuizProgress>>
  > = ({ signal }) =>
    getUserQuizProgress(quizId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!quizId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getUserQuizProgress>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetUserQuizProgressQueryResult = NonNullable<
  Awaited<ReturnType<typeof getUserQuizProgress>>
>;
export type GetUserQuizProgressQueryError = ErrorType<void>;

/**
 * @summary Get the current user's history for a specific quiz
 */

export function useGetUserQuizProgress<
  TData = Awaited<ReturnType<typeof getUserQuizProgress>>,
  TError = ErrorType<void>,
>(
  quizId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getUserQuizProgress>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetUserQuizProgressQueryOptions(quizId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
